(function (global) {
  'use strict';

  function pad(value) {
    return String(value).padStart(2, '0');
  }

  function Dayjs(dateInput) {
    this._date = dateInput ? new Date(dateInput) : new Date();
  }

  Dayjs.prototype.format = function (formatStr) {
    if (isNaN(this._date.getTime())) {
      return '';
    }

    var yyyy = this._date.getFullYear();
    var mm = pad(this._date.getMonth() + 1);
    var dd = pad(this._date.getDate());
    var hh = pad(this._date.getHours());
    var mi = pad(this._date.getMinutes());
    var ss = pad(this._date.getSeconds());

    return (formatStr || 'YYYY-MM-DD HH:mm:ss')
      .replace('YYYY', String(yyyy))
      .replace('MM', mm)
      .replace('DD', dd)
      .replace('HH', hh)
      .replace('mm', mi)
      .replace('ss', ss);
  };

  function dayjs(dateInput) {
    return new Dayjs(dateInput);
  }

  global.dayjs = dayjs;
})(window);
